func myHopsViewHref(orgID int64, viewKey string) string {
	return "/my-hops?org_id=" + strconv.FormatInt(orgID, 10) + "&view=" + viewKey
}

func myHopsRedirectHref(orgID int64, viewKey string) string {
	return myHopsViewHref(orgID, viewKey)
}

func myHopsDetailHref(orgID, hopID int64, viewKey string) string {
	return "/hops/view?hop_id=" + strconv.FormatInt(hopID, 10) + "&org_id=" + strconv.FormatInt(orgID, 10) + "&from=my-hops&view=" + viewKey
}

func myHopsPrimarySummary(hop types.Hop, viewKey string) string {
	switch viewKey {
	case "helped":
		if hop.Status == types.HopStatusCompleted && hop.CreatedByName != "" {
			return "You helped " + hop.CreatedByName
		}
		if hop.CreatedByName != "" {
			return "Requested by " + hop.CreatedByName
		}
		return "Hop you are helping with"
	case "offered":
		if hop.CreatedByName != "" {
			return "Offer sent to " + hop.CreatedByName
		}
		return "Offer awaiting a response"
	default:
		switch hop.Status {
		case types.HopStatusCompleted:
			if hop.AcceptedByName != nil && *hop.AcceptedByName != "" {
				return "Completed with " + *hop.AcceptedByName
			}
			return "Completed hop"
		case types.HopStatusAccepted:
			if hop.AcceptedByName != nil && *hop.AcceptedByName != "" {
				return *hop.AcceptedByName + " is helping with this hop"
			}
			return "A member is helping with this hop"
		default:
			if hop.HasPendingOffer {
				return "Someone has offered to help"
			}
			return "Waiting for a helper"
		}
	}
}

func myHopsSecondarySummary(hop types.Hop, viewKey string) string {
	if hop.EstimatedHours == 1 {
		return "Estimated: 1 hour"
	}
	return "Estimated: " + strconv.Itoa(hop.EstimatedHours) + " hours"
}

func myHopsHighlightCount(viewKey string, hops []types.Hop) int {
	switch viewKey {
	case "offered":
		return len(hops)
	case "helped":
		count := 0
		for _, hop := range hops {
			if hop.Status == types.HopStatusAccepted {
				count++
			}
		}
		return count
	default:
		count := 0
		for _, hop := range hops {
			if hop.Status == types.HopStatusOpen || hop.Status == types.HopStatusAccepted || hop.HasPendingOffer {
				count++
			}
		}
		return count
	}
}

func myHopsHighlightLabel(viewKey string) string {
	switch viewKey {
	case "offered":
		return "awaiting reply"
	case "helped":
		return "active"
	default:
		return "need attention"
	}
}

